const rows = $input.all();
let previous_prompt = '';
let chain_image_url = '';
let character_prompt_sheet = '';
if (rows.length > 0) {
  const last = rows[rows.length - 1].json;
  previous_prompt = String(last.sora_prompt ?? last.topic ?? '').trim();
  chain_image_url = String(last.chain_image_url ?? '').trim();
  character_prompt_sheet = String(last.character_prompt ?? '').trim();
}
const nextEpisode = rows.length + 1;

const DEFAULT_CHARACTER_PROMPT =
  'REPLACE_ME: your recurring AI-series protagonist (face, age, suit, insignia, body type) — English, one short paragraph';

const character_prompt = character_prompt_sheet || DEFAULT_CHARACTER_PROMPT;

const USD_DEEPSEEK = 0.002;
const USD_SORA = 0.45;
const USD_THUMB = 0.012;
const USD_NANO = 0.15;

const ARC_BEATS = [
  'BEAT 1 — ASTRONAUT HIRING: selection, medical, briefing, simulator; emotional hook of being accepted.',
  'BEAT 2 — FLIGHT TO SPACE: launch prep, liftoff, staging, first orbit; wonder and tension.',
  'BEAT 3 — DIFFICULTIES: anomaly, isolation, equipment fault, time pressure; stakes rise.',
  'BEAT 4 — SOLUTION: ingenuity, teamwork or solo breakthrough, calm under pressure; turning point.',
  'BEAT 5 — RETURN: re-entry, landing or homecoming, debrief, soft cliffhanger for next cycle.'
];
const beatIndex = (nextEpisode - 1) % ARC_BEATS.length;
const arc_beat = ARC_BEATS[beatIndex];

const system = [
  'You help produce ONE episode of a recurring YouTube Shorts vertical series (9:16). Output MUST use exactly these labels in English, in order, no text before TITLE:.',
  'TITLE: max 65 characters, click-worthy, matches the episode.',
  'DESCRIPTION: 2-4 short lines, friendly, one soft CTA (follow for next part), optional #Shorts; you may add one line saying visuals were AI-assisted if appropriate.',
  'TAGS: exactly 5 to 8 relevant lowercase keywords or short phrases, comma-separated, no #, no duplicates, niche-aligned (no random unrelated words).',
  'VIDEO_PROMPT: one paragraph only — English Sora-style scene: vertical 9:16, cinematic, strong hook in first second, clear subject and motion, ending on a beat the next episode can continue.',
  'THUMB_PROMPT: one line — English FLUX image prompt for a vertical cover: bold composition, high contrast, no text/letters in frame, same mood as the episode, eye-catching at small size.',
  '',
  'STORY_ARC: Each episode MUST center on the following beat (do not skip; weave prior events into it): ' + arc_beat,
  'CHARACTER_LOCK: The same protagonist as LOCKED_CHARACTER below must appear with consistent look (suit, face, proportions). Describe wardrobe and camera clearly.',
  'VISUAL_CHAIN: If PREVIOUS_VIDEO_PROMPT is non-empty, VIDEO_PROMPT must OPEN as direct continuation of its final beat (same story thread, same hero, same setting when possible). Otherwise start the pilot at an iconic moment of beat 1.',
  'CLOSE VIDEO_PROMPT on a transition or micro-cliffhanger. Safe content: no real celebrities, brands, gore, adult themes.'
].join('\n');

const user =
  'Episode number: ' +
  nextEpisode +
  '.\n\nLOCKED_CHARACTER (English; keep visually consistent across the whole series):\n' +
  character_prompt +
  '\n\n' +
  (previous_prompt
    ? 'PREVIOUS_VIDEO_PROMPT (continue from this ending):\n\n' +
      previous_prompt +
      '\n\nProduce TITLE, DESCRIPTION, TAGS, VIDEO_PROMPT, THUMB_PROMPT for the NEXT episode only.'
    : 'Series premiere (no prior VIDEO_PROMPT in sheet). Produce TITLE, DESCRIPTION, TAGS, VIDEO_PROMPT, THUMB_PROMPT for episode 1.');

return [
  {
    json: {
      nextEpisode,
      previous_prompt,
      chain_image_url,
      character_prompt,
      arc_beat,
      usd_deepseek_est: USD_DEEPSEEK,
      usd_sora_est: USD_SORA,
      usd_thumb_est: USD_THUMB,
      usd_nano_est: USD_NANO,
      usd_total_est: USD_DEEPSEEK + USD_SORA + USD_THUMB + USD_NANO,
      deepseekBody: {
        model: 'deepseek-chat',
        temperature: 0.85,
        max_tokens: 1200,
        messages: [
          { role: 'system', content: system },
          { role: 'user', content: user }
        ]
      }
    }
  }
];

const raw = $input.first().json.choices?.[0]?.message?.content;
const text = String(raw ?? '').trim();
function grab(label) {
  const re = new RegExp(label + ':\\s*([\\s\\S]*?)(?=\\n[A-Z_]+:|$)', 'i');
  const m = text.match(re);
  return m ? m[1].trim() : '';
}
const title = grab('TITLE') || 'AI Short';
const description = grab('DESCRIPTION') || '';
const tags_csv = grab('TAGS') || 'shorts, ai video, vertical';
const video_prompt = grab('VIDEO_PROMPT') || text;
const thumb_prompt = grab('THUMB_PROMPT') || ('Bold cinematic vertical key art, no text, high contrast, related to: ' + video_prompt.slice(0, 200));
const b = $('Build series + DeepSeek body + cost defaults').first().json;
return [{ json: {
  title,
  description,
  tags_csv,
  video_prompt,
  thumb_prompt,
  nextEpisode: b.nextEpisode,
  usd_deepseek_est: b.usd_deepseek_est,
  usd_sora_est: b.usd_sora_est,
  usd_thumb_est: b.usd_thumb_est,
  usd_nano_est: b.usd_nano_est,
  usd_total_est: b.usd_total_est,
  raw_deepseek: text
}}];

const p = $input.first().json;
const b = $('Build series + DeepSeek body + cost defaults').first().json;
const chainUrl = String(b.chain_image_url || '').trim();
const charLock = String(b.character_prompt || '').trim();
const sceneHint = String(p.video_prompt || '').slice(0, 900);

let nano_url = 'https://fal.run/fal-ai/nano-banana-pro';
let nano_body;

if (!chainUrl) {
  nano_body = {
    prompt:
      'Cinematic vertical 9:16 film still, photoreal, sharp focus, no text or watermark. Series character lock — must stay consistent in future episodes: ' +
      charLock +
      '. Scene for this Short (first frame of the clip): ' +
      sceneHint,
    num_images: 1,
    aspect_ratio: '9:16',
    output_format: 'png',
    resolution: '1K',
    safety_tolerance: '4'
  };
} else {
  nano_url = 'https://fal.run/fal-ai/nano-banana-pro/edit';
  nano_body = {
    image_urls: [chainUrl],
    prompt:
      'Same protagonist, face, suit details, and lighting style as the reference. Natural story progression — next moment in the same continuity. Vertical 9:16 keyframe, photoreal, no text. ' +
      sceneHint,
    num_images: 1,
    aspect_ratio: '9:16',
    output_format: 'png',
    resolution: '1K',
    safety_tolerance: '4'
  };
}

return [{ json: { ...p, nano_url, nano_body } }];

const base = $('Build Nano Banana keyframe request').first().json;
const img =
  $json.images?.[0]?.url ||
  $json.data?.images?.[0]?.url ||
  $json.image?.url ||
  '';
return [
  {
    json: {
      title: base.title,
      description: base.description,
      tags_csv: base.tags_csv,
      video_prompt: base.video_prompt,
      thumb_prompt: base.thumb_prompt,
      keyframe_url: img,
      nextEpisode: base.nextEpisode,
      usd_deepseek_est: base.usd_deepseek_est,
      usd_sora_est: base.usd_sora_est,
      usd_thumb_est: base.usd_thumb_est,
      usd_nano_est: base.usd_nano_est,
      usd_total_est: base.usd_total_est,
      raw_deepseek: base.raw_deepseek
    }
  }
];

const k = $('Merge keyframe + parse fields').first().json;
const img = $json.images?.[0]?.url || $json.data?.images?.[0]?.url || $json.image?.url || '';
return [{ json: { ...k, thumb_image_url: img } }];

